export const seedAptitudeQuestions = async () => {
  try {
    // Check if questions already exist
    const count = await AptitudeQuestion.countDocuments()
    if (count > 0) {
      console.log(`✓ Aptitude questions already seeded (${count} questions found)`)
      return
    }

    await AptitudeQuestion.insertMany(questionsData)
    console.log(`✓ Successfully seeded ${questionsData.length} aptitude questions`)
  } catch (error) {
    console.error("Error seeding aptitude questions:", error.message)
  }
}
